module RefModule (
    input wire clk,
    input wire reset_in,
    input wire reset_enable,
    output reg reset_out
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk) begin
        if (reset_in || reset_enable) begin
            reset_out <= 1'b1;
        end else begin
            reset_out <= 1'b0;
        end
    end
endmodule
